def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        factor = 1.0
        for step in range(1, 7):
            if residual <= 0:
                score += 20 / (step**2)
            else:
                increment = (step * 2) / (residual + step)
                score += increment
            residual *= 0.7
            if step % 2 == 0:
                factor *= 0.95
            else:
                factor *= 1.05
        if capacity > 4 * item:
            factor *= 0.8
        elif capacity > 3 * item:
            factor *= 0.9
        elif capacity > 2 * item:
            factor *= 1.1
        else:
            factor *= 1.25
        penalty = 0
        for check in range(1, int(np.ceil(item))+2):
            mod_result = (capacity - check) % (check + 1)
            if mod_result == 0:
                penalty += 0.3 * check
            elif mod_result == 1:
                penalty -= 0.2 * check
            else:
                penalty += (-1)**check * 0.05 * check
            if i % 3 == 0 and check % 2 == 0:
                penalty += 0.1 * (check / (i+1))
        score = score * factor + penalty
        if score < 0:
            priorities[i] = 0
        elif score > 200:
            priorities[i] = 200
        else:
            priorities[i] = score
    return priorities
